type ProductFormState = {
  name: string;
  description: string;
  vendor: string;
  category: string;
  status: string;
};

const emptyProductForm: ProductFormState = {
  name: '',
  description: '',
  vendor: '',
  category: '',
  status: 'active',
};

function ProductFormDialog({
  open,
  project,
  product,
  onClose,
}: {
  open: boolean;
  project: Project | null;
  product?: Product | null;
  onClose: () => void;
}) {
  const queryClient = useQueryClient();
  const { showToast } = useToast();
  const [form, setForm] = useState<ProductFormState>(emptyProductForm);

  const mutation = useMutation({
    mutationFn: () => {
      if (!project) throw new Error('Project is required');
      const payload = {
        name: form.name.trim(),
        description: form.description.trim() || null,
        vendor: form.vendor.trim() || null,
        category: form.category.trim() || null,
        status: form.status,
      };
      return product ? updateProduct(product.id, payload) : createProduct(project.id, payload);
    },
    onSuccess: () => {
      if (project) queryClient.invalidateQueries({ queryKey: ['products', project.id] });
      showToast(product ? 'Product updated' : 'Product created', 'success');
      onClose();
    },
    onError: (err: Error) => showToast(`Product save failed: ${err.message}`, 'error'),
  });

  const handleSubmit = (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    if (!form.name.trim()) return;
    mutation.mutate();
  };

  useEffect(() => {
    if (!open) return;
    setForm(
      product
        ? {
            name: product.name,
            description: product.description ?? '',
            vendor: product.vendor ?? '',
            category: product.category ?? '',
            status: product.status ?? 'active',
          }
        : emptyProductForm,
    );
  }, [open, product]);

  return (
    <Dialog
      open={open}
      onClose={() => {
        setForm(emptyProductForm);
        onClose();
      }}
      title={product ? 'Edit Product' : 'Create Product'}
      maxWidth="lg"
    >
      <form onSubmit={handleSubmit}>
        <DialogBody className="space-y-4">
          <Input
            label="Name"
            required
            value={form.name}
            onChange={(event) => setForm((current) => ({ ...current, name: event.target.value }))}
          />
          <Textarea
            label="Description"
            value={form.description}
            onChange={(event) => setForm((current) => ({ ...current, description: event.target.value }))}
          />
          <div className="grid gap-4 sm:grid-cols-3">
            <Input
              label="Vendor"
              value={form.vendor}
              onChange={(event) => setForm((current) => ({ ...current, vendor: event.target.value }))}
            />
            <Input
              label="Category"
              value={form.category}
              onChange={(event) => setForm((current) => ({ ...current, category: event.target.value }))}
            />
            <Select
              label="Status"
              value={form.status}
              onChange={(event) => setForm((current) => ({ ...current, status: event.target.value }))}
            >
              <option value="active">Active</option>
              <option value="maintenance">Maintenance</option>
              <option value="retired">Retired</option>
            </Select>
          </div>
        </DialogBody>
        <DialogFooter>
          <Button
            variant="secondary"
            onClick={() => {
              setForm(emptyProductForm);
              onClose();
            }}
          >
            Cancel
          </Button>
          <Button type="submit" loading={mutation.isPending} disabled={!form.name.trim()}>
            {product ? 'Save Product' : 'Create Product'}
          </Button>
        </DialogFooter>
      </form>
    </Dialog>
  );
}

