                </div>
              </div>

              <div className="overflow-hidden rounded-lg border border-hcl-border">
                <Table striped ariaLabel="VEX statements">
                  <TableHead>
                    <tr>
                      <Th>Vulnerability</Th>
                      <Th>Component</Th>
                      <Th>Status</Th>
                      <Th>Source</Th>
                      <Th>Evidence</Th>
                      <Th className="text-right">Actions</Th>
                    </tr>
                  </TableHead>
                  <TableBody>
                    {vexLoading ? (
                      <SkeletonRow cols={6} />
