              </option>
            ))}
	          </Select>

	          <Select
	            label="Product"
	            placeholder="Select a product..."
	            required
	            value={selectedProductId || ''}
	            disabled={!selectedProjectId || selectedProductsQuery.isLoading}
	            onChange={(e) => setSelectedProductId(e.target.value ? Number(e.target.value) : null)}
	          >
	            {selectedProductsQuery.data?.items.map((p) => (
	              <option key={p.id} value={p.id}>
	                {p.name}
	              </option>
	            ))}
	          </Select>

          <Input
            label="Change Reason"
            placeholder="e.g. Initial project assignment / migration to new workspace"
            value={assignChangeReason}
            onChange={(e) => setAssignChangeReason(e.target.value)}
          />
        </DialogBody>
      </Dialog>

      {/* EDIT DETAILS DIALOG */}
      <Dialog
        open={isEditDetailsModalOpen}
        onClose={() => setIsEditDetailsModalOpen(false)}
        title="Edit SBOM Details"
        maxWidth="lg"
        footer={
          <div className="flex items-center justify-end gap-2 px-6 py-4">
            <Button size="sm" variant="ghost" onClick={() => setIsEditDetailsModalOpen(false)}>
              Cancel
            </Button>
            <Button size="sm" onClick={handleEditDetailsSubmit} loading={isSavingDetails}>
              Save Details
            </Button>
          </div>
        }
      >
        <DialogBody className="space-y-4">
          {detailsError && (
            <div className="rounded-lg border border-red-200 bg-red-50 p-3 text-xs font-medium text-red-800">
              {detailsError}
            </div>
          )}

          <div className="grid grid-cols-2 gap-4">
            <Input
              label="SBOM Name"
              required
              value={detailName}
              onChange={(e) => setDetailName(e.target.value)}
            />
            <Select
              label="Project"
              placeholder="Select project..."
              value={detailProjectId || ''}
	              onChange={(e) => {
	                setDetailProjectId(e.target.value ? Number(e.target.value) : null);
	                setDetailProductId(null);
	              }}
	            >
              {projects?.map((p) => (
                <option key={p.id} value={p.id}>
                  {p.project_name}
                </option>
              ))}
	            </Select>
	          </div>

	          <div className="grid grid-cols-3 gap-4">
	            <Select
	              label="Product"
	              placeholder="Select product..."
	              value={detailProductId || ''}
	              disabled={!detailProjectId || detailProductsQuery.isLoading}
	              onChange={(e) => setDetailProductId(e.target.value ? Number(e.target.value) : null)}
	            >
	              {detailProductsQuery.data?.items.map((p) => (
	                <option key={p.id} value={p.id}>
	                  {p.name}
	                </option>
	              ))}
	            </Select>
            <Input
              label="Product Version"
              value={detailProductVersion}
              onChange={(e) => setDetailProductVersion(e.target.value)}
            />
            <Input
              label="SBOM Version"
              value={detailSbomVersion}
              onChange={(e) => setDetailSbomVersion(e.target.value)}
            />
          </div>

          <Textarea
            label="Description"
            placeholder="Add description..."
            value={detailDescription}
            onChange={(e) => setDetailDescription(e.target.value)}
          />

          <Input
            label="Change Reason"
            placeholder="e.g. Correcting metadata or project workspace"
            value={detailChangeReason}
            onChange={(e) => setDetailChangeReason(e.target.value)}
          />
        </DialogBody>
      </Dialog>
    </div>
  );
}

// @vitest-environment jsdom

import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { fireEvent, render, screen, waitFor } from '@testing-library/react';
import type { ReactNode } from 'react';
import { beforeEach, describe, expect, it, vi } from 'vitest';
import { HttpError } from '@/lib/api';

const push = vi.fn();
const useUploadSbomMutate = vi.fn();
const showToast = vi.fn();
const getSbomTypes = vi.fn();
const getProducts = vi.fn();

vi.mock('next/navigation', () => ({
  useRouter: () => ({ push, replace: vi.fn(), back: vi.fn() }),
}));

vi.mock('@/hooks/useSbomMutations', () => ({
  useUploadSbom: () => ({ mutate: useUploadSbomMutate, isPending: false }),
}));

vi.mock('@/hooks/useToast', () => ({
  useToast: () => ({ showToast }),
}));

vi.mock('@/hooks/useSbomsList', () => ({
  useSbomsList: () => ({ data: [] }),
}));

vi.mock('@/lib/api', async () => {
  const actual = await vi.importActual<typeof import('@/lib/api')>('@/lib/api');
  return {
    ...actual,
    getProjects: vi.fn().mockResolvedValue([
      {
        id: 42,
        project_name: 'Payments',
        project_details: null,
        project_status: 1,
        created_by: null,
        created_on: null,
        modified_by: null,
        modified_on: null,
      },
    ]),
    getProducts: (...args: unknown[]) => getProducts(...args),
    getSbomTypes: (...args: unknown[]) => getSbomTypes(...args),
  };
});

import { SbomUploadModal } from '@/components/sboms/SbomUploadModal';

function wrap(children: ReactNode) {
  const client = new QueryClient({
    defaultOptions: { queries: { retry: false, gcTime: 0, staleTime: 0 } },
  });
  return <QueryClientProvider client={client}>{children}</QueryClientProvider>;
}

beforeEach(() => {
  push.mockReset();
  useUploadSbomMutate.mockReset();
  showToast.mockReset();
  getSbomTypes.mockReset();
  getProducts.mockReset();
  getSbomTypes.mockResolvedValue([]);
  getProducts.mockResolvedValue([
    {
      id: 77,
      tenant_id: 1,
      project_id: 42,
      name: 'Payments API',
      slug: 'payments-api',
      description: null,
      sbom_count: 0,
    },
  ]);
  vi.restoreAllMocks();
});

async function fillRequiredFieldsAndSubmit(name: string, content = '{"bomFormat":"CycloneDX","specVersion":"1.5","components":[]}') {
  expect(await screen.findByRole('option', { name: 'Payments' })).toBeInTheDocument();
  fireEvent.change(screen.getByLabelText(/SBOM Name/i), { target: { value: name } });
  fireEvent.change(screen.getByLabelText(/Project/i), { target: { value: '42' } });
  const productOption = await screen.findByRole('option', { name: 'Payments API' });
  fireEvent.change(productOption.closest('select')!, { target: { value: '77' } });
  fireEvent.change(screen.getByPlaceholderText('Paste a small SPDX, CycloneDX, or XML SBOM preview'), {
    target: { value: content },
  });
  fireEvent.click(screen.getByRole('button', { name: /Upload SBOM/i }));
}

describe('SbomUploadModal validation repair handoff', () => {
  it('defaults the format selector to Auto-detect', async () => {
    getSbomTypes.mockResolvedValue([
      { id: 1, typename: 'CycloneDX JSON' },
      { id: 2, typename: 'SPDX JSON' },
    ]);

    render(wrap(<SbomUploadModal open onClose={vi.fn()} />));

    const formatSelect = await screen.findByLabelText(/SBOM Type \/ Format/i);
    expect(formatSelect).toHaveValue('');
    expect(screen.getByRole('option', { name: 'Auto-detect' })).toBeInTheDocument();
  });

  it('keeps the selected product in sync with form validation', async () => {
    render(wrap(<SbomUploadModal open onClose={vi.fn()} initialProjectId={42} initialProductId={77} />));

    await screen.findByRole('option', { name: 'Payments API' });
    const projectSelect = screen.getByRole('combobox', { name: /Project/i });
    const productSelect = screen.getByRole('combobox', { name: /^Product/i });
    await waitFor(() => expect(projectSelect).toHaveValue('42'));
    await waitFor(() => expect(productSelect).toHaveValue('77'));

    fireEvent.change(productSelect, { target: { value: '77' } });
    expect(screen.queryByText('Product is required')).not.toBeInTheDocument();
  });

  it('detects SPDX JSON content and selects the matching SPDX type', async () => {
    getSbomTypes.mockResolvedValue([
      { id: 1, typename: 'CycloneDX JSON' },
      { id: 2, typename: 'SPDX JSON' },
    ]);

    render(wrap(<SbomUploadModal open onClose={vi.fn()} />));

    const editor = screen.getByPlaceholderText('Paste a small SPDX, CycloneDX, or XML SBOM preview');
    fireEvent.change(editor, {
      target: {
        value: '{"spdxVersion":"SPDX-2.3","SPDXID":"SPDXRef-DOCUMENT","packages":[]}',
      },
    });

    expect(await screen.findByText(/SPDX JSON SPDX-2.3/i)).toBeInTheDocument();
    await waitFor(() => expect(screen.getByLabelText(/SBOM Type \/ Format/i)).toHaveValue('2'));
  });

  it('does not default unknown JSON to CycloneDX', async () => {
    getSbomTypes.mockResolvedValue([
      { id: 1, typename: 'CycloneDX JSON' },
      { id: 2, typename: 'SPDX JSON' },
    ]);

    render(wrap(<SbomUploadModal open onClose={vi.fn()} />));

    fireEvent.change(screen.getByPlaceholderText('Paste a small SPDX, CycloneDX, or XML SBOM preview'), {
      target: { value: '{"ok":false,"dependencyCount":10052}' },
    });

    expect(await screen.findByText(/Format could not be detected automatically/i)).toBeInTheDocument();
    expect(screen.getByLabelText(/SBOM Type \/ Format/i)).toHaveValue('');
  });

  it('does not send a CycloneDX type by default', async () => {
    getSbomTypes.mockResolvedValue([
      { id: 1, typename: 'CycloneDX JSON' },
      { id: 2, typename: 'SPDX JSON' },
    ]);
    useUploadSbomMutate.mockImplementation((_payload, _handlers) => {});

    render(wrap(<SbomUploadModal open onClose={vi.fn()} />));

    expect(await screen.findByRole('option', { name: 'Payments' })).toBeInTheDocument();
    fireEvent.change(screen.getByLabelText(/SBOM Name/i), { target: { value: 'unknown-sbom' } });
    fireEvent.change(screen.getByLabelText(/Project/i), { target: { value: '42' } });
    const productOption = await screen.findByRole('option', { name: 'Payments API' });
    fireEvent.change(productOption.closest('select')!, { target: { value: '77' } });
    fireEvent.change(screen.getByPlaceholderText('Paste a small SPDX, CycloneDX, or XML SBOM preview'), {
      target: { value: '{"ok":false}' },
    });
    fireEvent.click(screen.getByRole('button', { name: /Upload SBOM/i }));

    await waitFor(() => expect(useUploadSbomMutate).toHaveBeenCalled());
    expect(useUploadSbomMutate.mock.calls[0][0].sbom_type).toBeUndefined();
  });

  it('submits SBOM Version and Product Version as distinct metadata fields', async () => {
    useUploadSbomMutate.mockImplementation((_payload, _handlers) => {});

    render(wrap(<SbomUploadModal open onClose={vi.fn()} />));

    expect(await screen.findByRole('option', { name: 'Payments' })).toBeInTheDocument();
    fireEvent.change(screen.getByLabelText(/SBOM Name/i), { target: { value: 'manual-metadata' } });
    fireEvent.change(screen.getByLabelText(/Project/i), { target: { value: '42' } });
    const productOption = await screen.findByRole('option', { name: 'Payments API' });
    fireEvent.change(productOption.closest('select')!, { target: { value: '77' } });
    fireEvent.change(screen.getByLabelText(/SBOM Version/i), { target: { value: '1.1.1' } });
    fireEvent.change(screen.getByLabelText(/Product Version/i), { target: { value: '1.0.0' } });
    fireEvent.change(screen.getByLabelText(/Created By/i), { target: { value: 'Feroze' } });
    fireEvent.change(screen.getByPlaceholderText('Paste a small SPDX, CycloneDX, or XML SBOM preview'), {
      target: { value: '{"bomFormat":"CycloneDX","specVersion":"1.5","components":[]}' },
    });
    fireEvent.click(screen.getByRole('button', { name: /Upload SBOM/i }));

    await waitFor(() => expect(useUploadSbomMutate).toHaveBeenCalled());
    expect(useUploadSbomMutate.mock.calls[0][0]).toEqual(
      expect.objectContaining({
        sbom_version: '1.1.1',
        product_version: '1.0.0',
        created_by: 'Feroze',
      }),
    );
    expect(useUploadSbomMutate.mock.calls[0][0]).not.toHaveProperty('productver');
  });

  it('closes valid uploads, refreshes upload surfaces, and does not open repair workspace', async () => {
    const onClose = vi.fn();
    const onSuccess = vi.fn();
    const invalidateSpy = vi.spyOn(QueryClient.prototype, 'invalidateQueries');
    useUploadSbomMutate.mockImplementation((_payload, handlers) => {
      handlers.onSuccess({
        id: 7,
        sbom_name: 'good-sbom',
        projectid: 42,
        project_id: 42,
        project_name: 'Payments',
        component_count: 1,
        status: 'validated',
        validation_status: 'valid',
        workspace_id: 'valid-workspace-1',
        validation_session_id: 'valid-workspace-1',
        repair_workspace_url: '/repair/valid-workspace-1',
        enrichment_status: 'pending',
      });
    });

    render(wrap(<SbomUploadModal open onClose={onClose} onSuccess={onSuccess} />));

    await fillRequiredFieldsAndSubmit('good-sbom');

    await waitFor(() => {
      expect(showToast).toHaveBeenCalledWith(
        'SBOM uploaded and validated successfully.',
        'success',
        { duration: 5000 },
      );
    });
    expect(onClose).toHaveBeenCalledTimes(1);
    expect(onSuccess).toHaveBeenCalledWith(expect.objectContaining({ id: 7, enrichment_status: 'pending' }));
    expect(invalidateSpy).toHaveBeenCalledWith({ queryKey: ['sboms'] });
    expect(invalidateSpy).toHaveBeenCalledWith({ queryKey: ['dashboard-posture'] });
    expect(push).not.toHaveBeenCalled();
    expect(screen.queryByText(/Upload stored and validated/i)).not.toBeInTheDocument();
  });

  it('closes warning uploads, refreshes upload surfaces, and does not open repair workspace', async () => {
